import { Component } from '@angular/core';
import { Model } from './Model';

@Component({
  selector: 'app-root',  //AppComponenti uygulamammız içerisinde app-route olarak çağıracağım.
  templateUrl: './app.component.html', //app-route için kullanılıcak olan html sayfası
  styleUrls: ['./app.component.css']  //html sayfası için kullanılıcak olan css içerikleri nerde olacak
                                      //AppComponentin bileşenleri(css ve html)
})
export class AppComponent {
  title = 'SocialApp';
  model =new Model();

  getName(){
    return this.model.categoryName;
  }

  getProducts(){
    return this.model.products;
  }
}

<navbar></navbar>

<div calass="container">
  <div class="row">
    <div class="col-md-7">
      <h3 class="bg-primary text-white p-2"> {{getName()}} Katagorisi</h3>
      <table class="table table-bordered table-striped">
        <thead>
          <tr>
            <th>Id</th>
            <th>Name</th>
            <th>Price</th>
            <th></th>

          </tr>
        </thead>
        <tbody>
          <!-- burada isActive değerinin false olmasına göre tr tagına .bg-secondary clasını ekle yağıyoruz(ilgili satırların zeminlerinin gri olması gerekiyor) -->
          <tr *ngFor="let p of getProducts()" [class.bg-secondary]="p.isActive==false">
            <td>{{p.id}}</td>
            <td>{{p.name}}</td>
            <td>{{p.price}}</td>
            <td>
               <button class="btn btn-primary"> Edit</button>
               <button class="btn btn-danger"> Delete</button>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
